impl Solution { pub fn plates_between_candles(black_s: String, black_q: Vec<Vec<i32>>) -> Vec<i32> { let (black_n, black_b) = (black_s.len(), black_s.as_bytes()); let (mut black_p, mut black_l, mut black_r) = (vec![0; black_n + 1], vec![0; black_n], vec![0; black_n]); let (mut black_last_l, mut black_last_r) = (-1, -1); for i in 0..black_n { if black_b[i] == b'|' { black_last_l = i as i32; } black_l[i] = black_last_l; black_p[i + 1] = black_p[i] + (if black_b[i] == b'*' { 1 } else { 0 }); } for i in (0..black_n).rev() { if black_b[i] == b'|' { black_last_r = i as i32; } black_r[i] = black_last_r; } black_q.iter().map(|q| { let (i, j) = (black_r[q[0] as usize], black_l[q[1] as usize]); if i != -1 && j != -1 && i < j { black_p[j as usize] - black_p[i as usize] } else { 0 } }).collect() } }